sql:
SELECT COUNT(*) 
FROM studies 
WHERE study_status = 'ongoing';

SELECT principal_investigator, COUNT(study_id) AS number_of_studies
FROM studies
GROUP BY principal_investigator;

SELECT study_id, COUNT(sample_id) AS number_of_samples
FROM samples
GROUP BY study_id;

SELECT AVG(sample_count) AS average_samples_per_study
FROM (
    SELECT COUNT(sample_id) AS sample_count
    FROM samples
    GROUP BY study_id
) AS sample_counts;

SELECT study_title, start_date 
FROM studies 
ORDER BY start_date;

SELECT file_type, AVG(file_size) AS average_file_size
FROM data_files
GROUP BY file_type;

SELECT study_title, description
FROM studies
ORDER BY created_date DESC;
